const App = () => {
  const course = {
    name: 'Half Stack application development',
    parts: [
      {
        name: 'Fundamentals of React',
        exercises: 10
      },
      {
        name: 'Using props to pass data',
        exercises: 7
      },
      {
        name: 'State of a component',
        exercises: 14
      }
    ]
  }
  return (
    <div>
      <Header course={course.name} />

      {/* <ContentMix partContentParse={parts} /> */}
      {/* <Content contentTogether={course} />
       */}
      <Content content={course.parts} />
      {/* <Total contentNumber={parts} />/ */}
      <Total parts={course.parts} />
      {/* <Content name={part1.name} exercises={part1.exercises} />

      <Content name={part2.name} exercises={part2.exercises} />
      <Content name={part3.name} exercises={part3.exercises} />
      <Total exercises1={exercises1} exercises2={exercises2} exercises3={exercises3} /> */}
    </div >
  )
}
const Header = (props) => {
  console.log(props)
  return (
    <h1>{props.course}</h1>
  )
}
const ContentMix = (props) => {
  return (
    <p>
      {props.partContentMix.name} {props.partContentMix.exercises}
    </p>
  )
}

const Content = (props) => {
  return (
    <>
      <ContentMix partContentMix={props.content[0]} />
      <ContentMix partContentMix={props.content[1]} />
      <ContentMix partContentMix={props.content[2]} />
    </>
  )
}

const Total = props => (
  <p>
    Number of exercises{' '}
    {props.parts.reduce((total, part) => part.exercises + total, 0)}
  </p>
)
export default App
